firmware_template.source:
#include "lsm6ds3.h"
#include <Wire.h>
#include <Adafruit_LSM6DS3TRC.h>
static Adafruit_LSM6DS3TRC lsm;
static float _ax=0,_ay=0,_az=0,_gx=0,_gy=0,_gz=0;
static unsigned long _last=0;
void lsm6ds3_setup(){Wire.begin();if(!lsm.begin_I2C()){Serial.println("[lsm6ds3] Fail!");return;}Serial.println("[lsm6ds3] OK");}
void lsm6ds3_loop(){if(millis()-_last<50)return;_last=millis();sensors_event_t a,g,t;lsm.getEvent(&a,&g,&t);_ax=a.acceleration.x;_ay=a.acceleration.y;_az=a.acceleration.z;_gx=g.gyro.x;_gy=g.gyro.y;_gz=g.gyro.z;}
float lsm6ds3_get_accel_x(){return _ax;}
float lsm6ds3_get_accel_y(){return _ay;}
float lsm6ds3_get_accel_z(){return _az;}
float lsm6ds3_get_gyro_x(){return _gx;}
float lsm6ds3_get_gyro_y(){return _gy;}
float lsm6ds3_get_gyro_z(){return _gz;}
